function sha(buf){return crypto.createHash("sha256").update(buf).digest("hex");}
function fail(msg){console.error("[phase2f4-bridge-completion] "+msg);process.exit(1);}
let changed=0,already=0;
for(const e of entries){
  const target=path.join(root,e.path),exists=fs.existsSync(target);
  if(exists){
    const current=fs.readFileSync(target),hash=sha(current);
    if(hash===e.after){already++;continue;}
    if(e.before===null)fail(e.path+" already exists with unexpected content");
    if(hash!==e.before)fail(e.path+" does not match the expected initiative-authority baseline (got "+hash+")");
  } else if(e.before!==null) fail(e.path+" is missing from the expected initiative-authority baseline");
  const data=Buffer.from(e.content,"base64");
  if(sha(data)!==e.after)fail("embedded payload checksum failed for "+e.path);
  fs.mkdirSync(path.dirname(target),{recursive:true});
  const tmp=target+".tmp-"+process.pid;
  fs.writeFileSync(tmp,data);fs.renameSync(tmp,target);
  try{fs.chmodSync(target,parseInt(e.mode,8));}catch(_){}
  changed++;
}
console.log("[phase2f4-bridge-completion] applied "+changed+" file(s); "+already+" already current.");
